sudo docker exec familyhub-api-1 sh -c 'export DATABASE_URL="postgresql://organize:$(cat /secrets/db_password)@db:5432/organize" && node -e "const{PrismaClient}=require(\"@prisma/client\");const b=require(\"bcrypt\");const p=new PrismaClient();(async()=>{const pw=await b.hash(\"organize123\",10);const users=[{username:\"user1\",name:\"User 1\",color:\"#3B82F6\",password:pw,role:\"admin\"},{username:\"user2\",name:\"User 2\",color:\"#EF4444\",password:pw,role:\"admin\"},{username:\"user3\",name:\"User 3\",color:\"#10B981\",password:pw,role:\"member\"},{username:\"user4\",name:\"User 4\",color:\"#F59E0B\",password:pw,role:\"member\"}];for(const u of users){await p.user.upsert({where:{username:u.username},update:{},create:u})}console.log(\"Seeded 4 users\");await p.\$disconnect()})()"'
